mapper.select:
SELECT lc.*, lmo.material_name as lamination_material_name, lmo.description as lamination_material_description, ppo.step_name as post_processing_step_name FROM lamination_compatibility lc LEFT JOIN lamination_material_options lmo ON lc.lamination_material_id = lmo.id LEFT JOIN post_processing_options ppo ON lc.post_processing_step_id = ppo.id
AND lc.foil_series LIKE CONCAT('%', #{foilSeries}, '%')
AND lc.post_processing_step_id = #{postProcessingStepId}
AND lc.lamination_material_id = #{laminationMaterialId}
AND lc.interface_type_id = #{interfaceTypeId}
AND lc.compatibility = #{compatibility}
AND lc.product_type LIKE CONCAT('%', #{productType}, '%')
AND lc.model_number LIKE CONCAT('%', #{modelNumber}, '%')
AND ( lc.foil_series LIKE CONCAT('%', #{search}, '%') OR lc.product_type LIKE CONCAT('%', #{search}, '%') OR lc.model_number LIKE CONCAT('%', #{search}, '%') )
ORDER BY lc.id DESC

SELECT DISTINCT lmo.*
FROM lamination_compatibility lc
JOIN lamination_material_options lmo ON lc.lamination_material_id = lmo.id
WHERE lc.foil_series = #{foilSeries}
  AND lc.post_processing_step_id = #{postProcessingStepId}
  AND lc.interface_type_id = #{interfaceTypeId}
  AND lc.compatibility IN ('V', '▷')
ORDER BY lmo.display_order ASC, lmo.id ASC

SELECT DISTINCT ppo.*
FROM lamination_compatibility lc
JOIN post_processing_options ppo ON lc.post_processing_step_id = ppo.id
WHERE lc.foil_series = #{foilSeries}
  AND lc.lamination_material_id = #{laminationMaterialId}
  AND lc.interface_type_id = #{interfaceTypeId}
  AND lc.compatibility IN ('V', '▷')
ORDER BY ppo.display_order ASC, ppo.id ASC

SELECT COALESCE(MAX(compatibility), 'X')
FROM lamination_compatibility
WHERE foil_series = #{foilSeries}
  AND post_processing_step_id = #{postProcessingStepId}
  AND lamination_material_id = #{laminationMaterialId}
  AND interface_type_id = #{interfaceTypeId}

SELECT lc.*, lmo.material_name as lamination_material_name, lmo.description as lamination_material_description, ppo.step_name as post_processing_step_name FROM lamination_compatibility lc LEFT JOIN lamination_material_options lmo ON lc.lamination_material_id = lmo.id LEFT JOIN post_processing_options ppo ON lc.post_processing_step_id = ppo.id
AND lc.foil_series LIKE CONCAT('%', #{foilSeries}, '%')
AND lc.product_type LIKE CONCAT('%', #{productType}, '%')
AND lc.model_number LIKE CONCAT('%', #{modelNumber}, '%')
AND lc.post_processing_step_id = #{postProcessingStepId}
AND lc.lamination_material_id = #{laminationMaterialId}
AND lc.compatibility = #{compatibility}
ORDER BY lc.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM lamination_compatibility lc


        AND lc.foil_series LIKE CONCAT('%', #{foilSeries}, '%')


        AND lc.product_type LIKE CONCAT('%', #{productType}, '%')


        AND lc.model_number LIKE CONCAT('%', #{modelNumber}, '%')


        AND lc.post_processing_step_id = #{postProcessingStepId}


        AND lc.lamination_material_id = #{laminationMaterialId}


        AND lc.compatibility = #{compatibility}

SELECT 
    lc.*,
    lmo.material_name as lamination_material_name,
    lmo.description as lamination_material_description,
    ppo.step_name as post_processing_step_name
FROM lamination_compatibility lc
LEFT JOIN lamination_material_options lmo ON lc.lamination_material_id = lmo.id
LEFT JOIN post_processing_options ppo ON lc.post_processing_step_id = ppo.id
WHERE lc.foil_series = #{foilSeries}
  AND lc.interface_type_id = #{interfaceTypeId}
  AND lc.post_processing_step_id = #{postProcessingStepId}
  AND lc.lamination_material_id = #{laminationMaterialId}

